import React, { useEffect, useRef, useState } from 'react';
import { Icon } from '@capital/component';
import { usePlayerStore } from '../../store/playerStore';
import { useSettingsStore } from '../../store/settingsStore';
import { getPicUrl } from '../../api/musicApi';
import { FavoriteButton, ModeButton, PlayControls, ProgressBar, VolumeControl } from './Controls';

export const FullPlayer: React.FC<{ onCollapse: () => void; onClose: () => void }> = ({
  onCollapse,
  onClose,
}) => {
  const song = usePlayerStore((s) => s.currentSong);
  const queue = usePlayerStore((s) => s.queue);
  const lyrics = usePlayerStore((s) => s.lyrics);
  const idx = usePlayerStore((s) => s.currentLyricIndex);
  const playSong = usePlayerStore((s) => s.playSong);
  const settings = useSettingsStore((s) => s.settings);
  const [cover, setCover] = useState('');
  const [tab, setTab] = useState<'lyric' | 'queue'>('lyric');
  const lyricListRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (song?.pic_id) {
      getPicUrl(song.pic_id, song.source, 500).then(setCover).catch(() => undefined);
    } else {
      setCover('');
    }
  }, [song?.pic_id, song?.source]);

  useEffect(() => {
    const el = lyricListRef.current?.querySelector<HTMLDivElement>(`[data-idx="${idx}"]`);
    el?.scrollIntoView({ block: 'center', behavior: 'smooth' });
  }, [idx]);

  return (
    <div
      style={{
        position: 'fixed',
        right: 16,
        bottom: 16,
        zIndex: 999999,
        width: 380,
        height: 560,
        borderRadius: 18,
        overflow: 'hidden',
        color: '#fff',
        boxShadow: '0 12px 32px rgba(0,0,0,0.4)',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      {/* 模糊背景 */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          backgroundImage: cover ? `url(${cover})` : 'linear-gradient(135deg,#667eea,#764ba2)',
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          filter: 'blur(30px) brightness(0.5)',
          transform: 'scale(1.2)',
          zIndex: -1,
        }}
      />
      <div style={{ position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.25)', zIndex: -1 }} />

      {/* 顶部栏 */}
      <div style={{ display: 'flex', alignItems: 'center', padding: '10px 14px' }}>
        <div style={{ fontWeight: 700, fontSize: 14 }}>正在播放</div>
        <div style={{ flex: 1 }} />
        <Icon
          icon="mdi:chevron-down"
          width={20}
          style={{ cursor: 'pointer', marginRight: 10, opacity: 0.85 }}
          onClick={onCollapse}
        />
        <Icon icon="mdi:close" width={18} style={{ cursor: 'pointer', opacity: 0.85 }} onClick={onClose} />
      </div>

      {tab === 'lyric' ? (
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '0 20px' }}>
          <img
            src={cover}
            style={{
              width: 140,
              height: 140,
              borderRadius: 12,
              objectFit: 'cover',
              boxShadow: '0 6px 20px rgba(0,0,0,0.4)',
              background: 'rgba(255,255,255,0.1)',
            }}
          />
          <div style={{ marginTop: 12, fontSize: 16, fontWeight: 700, textAlign: 'center' }}>
            {song?.name || '未播放'}
          </div>
          <div style={{ fontSize: 12, opacity: 0.7, marginTop: 2 }}>{song?.artist}</div>
        </div>
      ) : null}

      {/* 歌词 / 播放列表 切换区域 */}
      <div ref={lyricListRef} style={{ flex: 1, overflowY: 'auto', padding: '10px 20px', marginTop: tab === 'lyric' ? 6 : 0 }}>
        {tab === 'lyric' &&
          (lyrics.length > 0 ? (
            lyrics.map((line, i) => (
              <div
                key={i}
                data-idx={i}
                style={{
                  textAlign: 'center',
                  padding: '5px 0',
                  fontSize: i === idx ? settings.lyricSize : settings.lyricSize * 0.82,
                  fontWeight: i === idx ? 700 : 400,
                  color: i === idx ? settings.lyricHighlightColor : settings.lyricColor,
                  opacity: i === idx ? 1 : 0.55,
                  transition: 'all .2s',
                }}
              >
                {line.text || '·'}
                {settings.bilingualLyric && line.tran && (
                  <div style={{ fontSize: '0.8em', opacity: 0.8 }}>{line.tran}</div>
                )}
              </div>
            ))
          ) : (
            <div style={{ textAlign: 'center', opacity: 0.5, marginTop: 40 }}>暂无歌词</div>
          ))}

        {tab === 'queue' &&
          queue.map((s, i) => (
            <div
              key={`${s.source}-${s.id}`}
              onClick={() => playSong(s, queue)}
              style={{
                display: 'flex',
                alignItems: 'center',
                padding: '8px 6px',
                borderRadius: 8,
                cursor: 'pointer',
                background: s.id === song?.id && s.source === song?.source ? 'rgba(255,255,255,0.15)' : 'transparent',
              }}
            >
              <span style={{ width: 22, opacity: 0.5, fontSize: 12 }}>{i + 1}</span>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontSize: 13, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                  {s.name}
                </div>
                <div style={{ fontSize: 11, opacity: 0.6, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                  {s.artist}
                </div>
              </div>
            </div>
          ))}
      </div>

      {/* 控制区 */}
      <div style={{ padding: '10px 20px 16px' }}>
        <ProgressBar color={settings.lyricHighlightColor} />
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 10 }}>
          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
            <ModeButton color="#fff" />
            <FavoriteButton color="#fff" />
          </div>
          <PlayControls size={22} color="#fff" />
          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
            <VolumeControl color="#fff" />
            <Icon
              icon="mdi:playlist-music"
              width={18}
              color="#fff"
              style={{ cursor: 'pointer', opacity: tab === 'queue' ? 1 : 0.6 }}
              onClick={() => setTab(tab === 'queue' ? 'lyric' : 'queue')}
            />
          </div>
        </div>
      </div>
    </div>
  );
};
