import { sendMessage } from '@capital/common';
import { Playlist, Song } from '../const';

const SCHEME = 'tailchat-music';

function b64encode(str: string): string {
  try {
    return btoa(unescape(encodeURIComponent(str)));
  } catch {
    return '';
  }
}

export function b64decode(str: string): string {
  try {
    return decodeURIComponent(escape(atob(str)));
  } catch {
    return '';
  }
}

function buildUrl(type: string, params: Record<string, string>): string {
  const qs = Object.entries(params)
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
    .join('&');
  return `${SCHEME}://${type}?${qs}`;
}

export function buildSongCardContent(song: Song): string {
  const url = buildUrl('song', {
    source: song.source,
    id: song.id,
    name: song.name,
    artist: song.artist,
    album: song.album || '',
    pic: song.pic_id || '',
    lyric: song.lyric_id || '',
  });
  return `🎵 分享了歌曲《${song.name}》- ${song.artist}\n${url}`;
}

export function buildAlbumCardContent(song: Song): string {
  const url = buildUrl('album', {
    source: song.source,
    album: song.album,
    artist: song.artist,
    pic: song.pic_id || '',
  });
  return `💿 分享了专辑《${song.album}》- ${song.artist}\n${url}`;
}

export function buildArtistCardContent(song: Song): string {
  const url = buildUrl('artist', {
    source: song.source,
    artist: song.artist,
  });
  return `🎤 分享了歌手：${song.artist}\n${url}`;
}

export function buildPlaylistCardContent(playlist: Playlist): string {
  const data = b64encode(
    JSON.stringify(playlist.songs.slice(0, 30).map((s) => ({ i: s.id, s: s.source, n: s.name, a: s.artist, p: s.pic_id, l: s.lyric_id, al: s.album })))
  );
  const url = buildUrl('playlist', {
    name: playlist.name,
    count: String(playlist.songs.length),
    data,
  });
  return `🎶 分享了歌单《${playlist.name}》(${playlist.songs.length}首)\n${url}`;
}

export interface ParsedMusicCard {
  type: 'song' | 'album' | 'artist' | 'playlist';
  params: Record<string, string>;
}

const CARD_RE = /tailchat-music:\/\/(song|album|artist|playlist)\?([^\s]+)/;

export function parseMusicCardFromContent(content: string): ParsedMusicCard | null {
  const match = content.match(CARD_RE);
  if (!match) return null;
  const [, type, qs] = match;
  const params: Record<string, string> = {};
  qs.split('&').forEach((pair) => {
    const [k, v] = pair.split('=');
    if (k) params[decodeURIComponent(k)] = decodeURIComponent(v || '');
  });
  return { type: type as ParsedMusicCard['type'], params };
}

export async function shareToConverse(
  content: string,
  converseId: string,
  groupId?: string
) {
  return sendMessage({ converseId, groupId, content, plain: content.split('\n')[0] });
}
