import React, { useEffect, useRef, useState } from 'react';
import { usePlayerStore } from '../../store/playerStore';
import { useSettingsStore } from '../../store/settingsStore';
import { getPicUrl } from '../../api/musicApi';

/**
 * 面板右侧栏: 专辑封面 + 滚动歌词
 * 对应设计参考图中右侧「专辑封面 / 歌词」区域
 */
export const Sidebar: React.FC = () => {
  const song = usePlayerStore((s) => s.currentSong);
  const lyrics = usePlayerStore((s) => s.lyrics);
  const idx = usePlayerStore((s) => s.currentLyricIndex);
  const settings = useSettingsStore((s) => s.settings);
  const [cover, setCover] = useState('');
  const listRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (song?.pic_id) {
      getPicUrl(song.pic_id, song.source, 500).then(setCover).catch(() => undefined);
    } else {
      setCover('');
    }
  }, [song?.pic_id, song?.source]);

  useEffect(() => {
    const el = listRef.current?.querySelector<HTMLDivElement>(`[data-idx="${idx}"]`);
    el?.scrollIntoView({ block: 'center', behavior: 'smooth' });
  }, [idx]);

  return (
    <div
      style={{
        width: 260,
        flexShrink: 0,
        borderLeft: '1px solid rgba(120,120,120,0.2)',
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
      }}
    >
      <div style={{ padding: 16, display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
        <div
          style={{
            width: 180,
            height: 180,
            borderRadius: 10,
            overflow: 'hidden',
            background: 'linear-gradient(135deg,#667eea,#764ba2)',
            boxShadow: '0 6px 18px rgba(0,0,0,0.25)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          {cover ? (
            <img src={cover} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
          ) : (
            <span style={{ color: 'rgba(255,255,255,0.6)', fontSize: 12 }}>专辑封面</span>
          )}
        </div>
        <div style={{ marginTop: 10, fontWeight: 700, fontSize: 14, textAlign: 'center' }}>
          {song?.name || '未播放任何歌曲'}
        </div>
        <div style={{ fontSize: 12, opacity: 0.55, textAlign: 'center', marginTop: 2 }}>
          {song?.artist || ''}
        </div>
      </div>

      <div
        ref={listRef}
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: '4px 14px 14px',
          borderTop: '1px solid rgba(120,120,120,0.15)',
        }}
      >
        {lyrics.length === 0 && (
          <div style={{ textAlign: 'center', opacity: 0.4, marginTop: 30, fontSize: 13 }}>暂无歌词</div>
        )}
        {lyrics.map((line, i) => (
          <div
            key={i}
            data-idx={i}
            style={{
              textAlign: 'center',
              padding: '5px 0',
              fontSize: i === idx ? settings.lyricSize * 0.72 : settings.lyricSize * 0.6,
              fontWeight: i === idx ? 700 : 400,
              color: i === idx ? settings.lyricHighlightColor : 'inherit',
              opacity: i === idx ? 1 : 0.5,
              transition: 'all .2s',
            }}
          >
            {line.text || '·'}
            {settings.bilingualLyric && line.tran && (
              <div style={{ fontSize: '0.82em', opacity: 0.8 }}>{line.tran}</div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};
