import React, { useState } from 'react';
import { Icon } from '@capital/component';
import { showToasts } from '@capital/common';
import { Song } from '../../const';
import { addSongToPlaylist, createPlaylist, getPlaylists } from '../../utils/storage';

export const AddToPlaylistMenu: React.FC<{ song: Song }> = ({ song }) => {
  const [open, setOpen] = useState(false);
  const [playlists, setPlaylists] = useState(getPlaylists());
  const [newName, setNewName] = useState('');

  return (
    <div style={{ position: 'relative' }}>
      <div
        style={{ cursor: 'pointer', display: 'flex', opacity: 0.8 }}
        title="添加到歌单"
        onClick={() => {
          setPlaylists(getPlaylists());
          setOpen((o) => !o);
        }}
      >
        <Icon icon="mdi:playlist-plus" width={18} />
      </div>
      {open && (
        <div
          style={{
            position: 'absolute',
            right: 0,
            top: 24,
            zIndex: 10,
            background: 'var(--tc-content-background-color,#222)',
            border: '1px solid rgba(120,120,120,0.3)',
            borderRadius: 8,
            width: 200,
            padding: 8,
            boxShadow: '0 6px 16px rgba(0,0,0,0.25)',
          }}
        >
          <div style={{ maxHeight: 160, overflowY: 'auto' }}>
            {playlists.length === 0 && <div style={{ opacity: 0.5, fontSize: 12, padding: 4 }}>暂无歌单</div>}
            {playlists.map((p) => (
              <div
                key={p.id}
                style={{ padding: '6px 4px', cursor: 'pointer', fontSize: 13 }}
                onClick={() => {
                  addSongToPlaylist(p.id, song);
                  showToasts(`已添加到《${p.name}》`, 'success');
                  setOpen(false);
                }}
              >
                {p.name}
              </div>
            ))}
          </div>
          <div style={{ display: 'flex', gap: 4, marginTop: 6, borderTop: '1px solid rgba(120,120,120,0.2)', paddingTop: 6 }}>
            <input
              value={newName}
              onChange={(e) => setNewName(e.target.value)}
              placeholder="新建歌单"
              style={{ flex: 1, fontSize: 12, padding: '4px 6px', borderRadius: 4, border: '1px solid rgba(120,120,120,0.3)', background: 'transparent', color: 'inherit' }}
            />
            <div
              style={{ cursor: 'pointer', display: 'flex', alignItems: 'center' }}
              onClick={() => {
                if (!newName.trim()) return;
                const pl = createPlaylist(newName.trim());
                addSongToPlaylist(pl.id, song);
                setNewName('');
                showToasts(`已创建并添加到《${pl.name}》`, 'success');
                setOpen(false);
              }}
            >
              <Icon icon="mdi:check" width={16} />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
