import React from 'react';
import { useSettingsStore } from '../../store/settingsStore';
import { MUSIC_SOURCES } from '../../const';

const row: React.CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  padding: '12px 4px',
  borderBottom: '1px solid rgba(120,120,120,0.15)',
  gap: 12,
};
const label: React.CSSProperties = { fontSize: 13, fontWeight: 500 };
const controlWrap: React.CSSProperties = { flexShrink: 0 };
const selectStyle: React.CSSProperties = {
  padding: '5px 8px',
  borderRadius: 6,
  border: '1px solid rgba(120,120,120,0.3)',
  background: 'transparent',
  color: 'inherit',
};
const section: React.CSSProperties = { fontSize: 12, opacity: 0.5, margin: '14px 4px 4px', fontWeight: 700 };

export const SettingsPanel: React.FC = () => {
  const { settings, update, reset } = useSettingsStore();

  return (
    <div style={{ height: '100%', overflowY: 'auto', padding: '4px 14px 24px' }}>
      <div style={section}>播放</div>

      <div style={row}>
        <span style={label}>默认播放器样式</span>
        <select
          style={selectStyle}
          value={settings.playerStyle}
          onChange={(e) => update({ playerStyle: e.target.value as any })}
        >
          <option value="mini">迷你条</option>
          <option value="lyrics">透明悬浮歌词</option>
          <option value="full">完整播放器</option>
        </select>
      </div>

      <div style={row}>
        <span style={label}>默认音乐源</span>
        <select
          style={selectStyle}
          value={settings.defaultSource}
          onChange={(e) => update({ defaultSource: e.target.value as any })}
        >
          {MUSIC_SOURCES.map((s) => (
            <option key={s.value} value={s.value}>
              {s.label}
            </option>
          ))}
        </select>
      </div>

      <div style={row}>
        <span style={label}>音质</span>
        <select
          style={selectStyle}
          value={settings.quality}
          onChange={(e) => update({ quality: Number(e.target.value) as any })}
        >
          <option value={128}>标准 128k</option>
          <option value={192}>较高 192k</option>
          <option value={320}>极高 320k</option>
          <option value={740}>无损 16bit</option>
          <option value={999}>无损 24bit</option>
        </select>
      </div>

      <div style={section}>媒体快捷键</div>

      <div style={row}>
        <span style={label}>开启媒体快捷键</span>
        <input
          type="checkbox"
          checked={settings.mediaKeysEnabled}
          onChange={(e) => update({ mediaKeysEnabled: e.target.checked })}
        />
      </div>

      {(['playPause', 'next', 'prev', 'volumeUp', 'volumeDown'] as const).map((key) => (
        <div style={row} key={key}>
          <span style={label}>
            {{
              playPause: '播放/暂停',
              next: '下一首',
              prev: '上一首',
              volumeUp: '增大音量',
              volumeDown: '减小音量',
            }[key]}
          </span>
          <input
            style={{ ...selectStyle, width: 120, textAlign: 'center' }}
            value={settings.shortcuts[key]}
            onKeyDown={(e) => {
              e.preventDefault();
              const parts: string[] = [];
              if (e.ctrlKey) parts.push('Ctrl');
              if (e.altKey) parts.push('Alt');
              if (e.shiftKey) parts.push('Shift');
              if (!['Control', 'Alt', 'Shift'].includes(e.key)) {
                parts.push(e.key.length === 1 ? e.key.toUpperCase() : e.key);
                update({ shortcuts: { ...settings.shortcuts, [key]: parts.join('+') } });
              }
            }}
            readOnly
            placeholder="点击后按下按键"
          />
        </div>
      ))}

      <div style={section}>歌词</div>

      <div style={row}>
        <span style={label}>歌词大小 ({settings.lyricSize}px)</span>
        <input
          type="range"
          min={12}
          max={36}
          value={settings.lyricSize}
          onChange={(e) => update({ lyricSize: Number(e.target.value) })}
        />
      </div>

      <div style={row}>
        <span style={label}>歌词颜色</span>
        <input
          type="color"
          value={settings.lyricColor}
          onChange={(e) => update({ lyricColor: e.target.value })}
        />
      </div>

      <div style={row}>
        <span style={label}>高亮颜色</span>
        <input
          type="color"
          value={settings.lyricHighlightColor}
          onChange={(e) => update({ lyricHighlightColor: e.target.value })}
        />
      </div>

      <div style={row}>
        <span style={label}>歌词/悬浮透明度</span>
        <input
          type="range"
          min={0.2}
          max={1}
          step={0.05}
          value={settings.floatingOpacity}
          onChange={(e) => update({ floatingOpacity: Number(e.target.value) })}
        />
      </div>

      <div style={row}>
        <span style={label}>双语歌词</span>
        <input
          type="checkbox"
          checked={settings.bilingualLyric}
          onChange={(e) => update({ bilingualLyric: e.target.checked })}
        />
      </div>

      <div style={row}>
        <span style={label}>锁定悬浮歌词位置</span>
        <input
          type="checkbox"
          checked={settings.floatingLocked}
          onChange={(e) => update({ floatingLocked: e.target.checked })}
        />
      </div>

      <div style={section}>主题</div>
      <div style={row}>
        <span style={label}>播放器主题</span>
        <select style={selectStyle} value={settings.theme} onChange={(e) => update({ theme: e.target.value as any })}>
          <option value="auto">跟随系统</option>
          <option value="light">浅色</option>
          <option value="dark">深色</option>
          <option value="colorful">炫彩</option>
        </select>
      </div>

      <div style={{ marginTop: 20, textAlign: 'center' }}>
        <span
          style={{ fontSize: 12, opacity: 0.5, cursor: 'pointer', textDecoration: 'underline' }}
          onClick={() => window.confirm('恢复默认设置?') && reset()}
        >
          恢复默认设置
        </span>
      </div>

      <div style={{ marginTop: 14, fontSize: 11, opacity: 0.35, textAlign: 'center' }}>
        音乐数据来源: GD音乐台 (music.gdstudio.xyz)，仅供学习交流使用
      </div>
    </div>
  );
};
