import React, { useEffect, useState } from 'react';
import { usePlayerStore } from '../../store/playerStore';
import { getPicUrl } from '../../api/musicApi';
import {
  FavoriteButton,
  ModeButton,
  PlayControls,
  ProgressBar,
  VolumeControl,
} from '../player/Controls';

/**
 * 面板底部常驻播放条: 上一首/播放暂停/下一首 + 进度 + 时间 + 音量 + 模式 + 收藏
 * 对应设计参考图底部横跨全宽的播放控制条
 */
export const TransportBar: React.FC = () => {
  const song = usePlayerStore((s) => s.currentSong);
  const [cover, setCover] = useState('');

  useEffect(() => {
    if (song?.pic_id) {
      getPicUrl(song.pic_id, song.source).then(setCover).catch(() => undefined);
    } else {
      setCover('');
    }
  }, [song?.pic_id, song?.source]);

  return (
    <div
      style={{
        borderTop: '1px solid rgba(120,120,120,0.2)',
        padding: '10px 16px',
        display: 'flex',
        alignItems: 'center',
        gap: 14,
      }}
    >
      <div
        style={{
          width: 36,
          height: 36,
          borderRadius: 6,
          flexShrink: 0,
          background: 'linear-gradient(135deg,#667eea,#764ba2)',
          overflow: 'hidden',
        }}
      >
        {cover && <img src={cover} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}
      </div>

      <div style={{ width: 140, flexShrink: 0, minWidth: 0 }}>
        <div style={{ fontSize: 12, fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
          {song?.name || '未播放'}
        </div>
        <div style={{ fontSize: 11, opacity: 0.55, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
          {song?.artist || ''}
        </div>
      </div>

      <PlayControls size={18} />

      <div style={{ flex: 1, minWidth: 120 }}>
        <ProgressBar />
      </div>

      <ModeButton />
      <FavoriteButton />
      <VolumeControl />
    </div>
  );
};
