import { API_BASE, MusicSource, Song } from '../const';

async function req<T = any>(params: Record<string, string | number>): Promise<T> {
  const qs = Object.entries(params)
    .filter(([, v]) => v !== undefined && v !== null && v !== '')
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join('&');
  const res = await fetch(`${API_BASE}?${qs}`);
  if (!res.ok) {
    throw new Error(`music api error: ${res.status}`);
  }
  return res.json();
}

export interface RawSearchItem {
  id: string;
  name: string;
  artist: string[];
  album: string;
  pic_id: string;
  url_id: string;
  lyric_id: string;
  source: MusicSource;
}

/**
 * 搜索歌曲 (关键字可以是曲目名/歌手名/专辑名)
 */
export async function searchMusic(
  keyword: string,
  source: MusicSource = 'netease',
  count = 30,
  pages = 1
): Promise<Song[]> {
  const list = await req<RawSearchItem[]>({
    types: 'search',
    source,
    name: keyword,
    count,
    pages,
  });

  if (!Array.isArray(list)) {
    return [];
  }

  return list.map((item) => ({
    id: String(item.id),
    source: item.source || source,
    name: item.name,
    artist: Array.isArray(item.artist) ? item.artist.join(' / ') : String(item.artist),
    album: item.album,
    pic_id: item.pic_id,
    lyric_id: item.lyric_id,
  }));
}

/**
 * 搜索专辑内曲目列表 (专辑用 `${source}_album`)
 */
export async function searchAlbumTracks(
  albumName: string,
  source: MusicSource = 'netease',
  count = 50
): Promise<Song[]> {
  return searchMusic(albumName, `${source}_album` as MusicSource, count);
}

/**
 * 获取播放直链
 */
export async function getSongUrl(
  id: string,
  source: MusicSource = 'netease',
  br: number | string = 320
): Promise<{ url: string; br: number; size: number }> {
  return req({ types: 'url', source, id, br });
}

/**
 * 获取专辑图
 */
export async function getPicUrl(
  picId: string,
  source: MusicSource = 'netease',
  size: 300 | 500 = 300
): Promise<string> {
  const data = await req<{ url: string }>({
    types: 'pic',
    source,
    id: picId,
    size,
  });
  return data.url;
}

/**
 * 获取歌词 (原语言 + 可能的翻译)
 */
export async function getLyric(
  lyricId: string,
  source: MusicSource = 'netease'
): Promise<{ lyric: string; tlyric?: string }> {
  return req({ types: 'lyric', source, id: lyricId });
}
