import React from 'react';
import { createRoot } from 'react-dom/client';
import { PlayerRoot } from './PlayerRoot';

let mounted = false;

/**
 * 将全局悬浮播放器挂载到 document.body 上的一个独立节点。
 *
 * 之前版本使用了 @capital/component 提供的 PortalAdd/PortalRemove，
 * 理论上可以复用宿主已挂载的 React 树、省掉 react-dom 的体积，但实际验证下来
 * 在当前宿主环境里不可见（可能是 PortalHost 未挂载在真正的页面根节点，或被
 * 某个祖先容器的 CSS 裁剪/层叠上下文影响）。为了保证悬浮播放器在任何情况下都
 * 稳定可见，改为与官方 com.msgbyte.widget.sakana 插件一致的做法：
 * 直接创建一个新节点挂到 document.body 上，完全独立于宿主应用的 DOM 结构。
 */
export function mountGlobalPlayer() {
  if (mounted) return;
  mounted = true;

  const container = document.createElement('div');
  container.id = 'tailchat-music-player-root';
  document.body.appendChild(container);

  const root = createRoot(container);
  root.render(<PlayerRoot />);
}
